-- Patchnote 0.7.3 — idempotent seed (ON CONFLICT DO NOTHING) so a dev DB that already carries
-- a manual 0.7.3 row stays untouched.
INSERT INTO "Patchnote" ("version", "type", "date", "titleEn", "titleFr", "entries") VALUES
('0.7.3', 'minor', '2026-04-26T00:00:00.000Z',
  'Composable admin dashboard + plugin install fix',
  'Dashboard admin composable + correctif install plugin',
  '[{"type":"feat","titleEn":"Composable admin dashboard","titleFr":"Dashboard admin composable","descEn":"Drag-and-drop widget grid replaces the static admin DashboardTab. Three built-in widgets ship out of the box (stats counters, service health, system version + plugin updates). Plugins can contribute their own widgets via the new admin.dashboard.widget hook point. Layout persists globally per Oscarr instance.","descFr":"La grille de widgets drag-and-drop remplace le DashboardTab statique. Trois widgets natifs disponibles (compteurs de stats, santé des services, version + updates plugins). Les plugins peuvent contribuer leurs propres widgets via le nouveau hook admin.dashboard.widget. Le layout est persisté globalement par instance Oscarr."},{"type":"feat","titleEn":"WYSIWYG widget edit mode","titleFr":"Mode édition WYSIWYG","descEn":"Editing the dashboard no longer wraps each widget in an extra card. Drag handle and remove button float in the corners with a dashed outline — what you see in edit is what you get in view.","descFr":"En mode édition, les widgets ne sont plus encapsulés dans une card supplémentaire. La poignée de drag et le bouton supprimer flottent dans les coins avec un liseré tireté — ce que tu vois en édition est ce que tu auras en lecture."},{"type":"fix","titleEn":"Plugin install across filesystems","titleFr":"Install plugin cross-filesystem","descEn":"In Docker setups where /tmp lives on a tmpfs mount and /app on the persistent volume, the install used to fail with EXDEV (cross-device link). Plugin tarballs now stage inside the plugins directory itself so the final rename stays atomic.","descFr":"Dans une install Docker où /tmp est un montage tmpfs et /app sur le volume persistant, l''install échouait avec EXDEV (cross-device link). Les tarballs sont maintenant stagés dans le dossier plugins lui-même pour que le rename final reste atomique."}]'
) ON CONFLICT ("version") DO NOTHING;
